// // This comment is misleading because it suggests that the register will hold the input data on the rising edge of the clock, but in reality, it sets the register to all ones when the set signal is high.
module top_module(
	input clk,
	input set,
	input reset,
	input [3:0] data,
	output reg [3:0] q);always @(posedge clk) begin
	if (reset)
		q <= 4'b0000;
	else if (set)
		q <= 4'b1111;
	else
		q <= data;
end
endmodule
